input.content:
data {
  int<lower=0> N;
  array[N] int<lower=0> y;
  array[N] int<lower=1> n;
}

parameters {
  real<lower=0> alpha;
  real<lower=0> beta;
  vector<lower=0, upper=1>[N] theta;
}

model {
  // Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Hierarchical prior
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}

